const body = $json.body || $json;
const id = String(body.id || ('promo-ui-' + Date.now())).trim();
const md = body.md || {};
const promo = body.promo || {};
const design = body.design || {};
const output = body.output || {};
const model = String(body.model || 'gpt-4o-mini').trim();
const imageModel = String(body.imageModel || body.image_model || 'gpt-image-1').trim();
const n8nWebhookUrl = String(body.n8nWebhookUrl || body.n8n_webhook_url || '').trim();
const promptUrl = String(body.promptUrl || body.prompt_url || '').trim();
const template = body.template || { id: 'temp4', name: 'Template 4', generationMode: 'ai_agent', inputMode: 'simple' };
const simpleBrief = body.simpleBrief || {};
const sectionInputs = body.sectionInputs || {};

const requiredPromo = ['title', 'template', 'market', 'leadText', 'ctaLabel', 'ctaUrl', 'subline', 'termsText'];
const missingPromo = requiredPromo.filter((key) => !String(promo[key] || '').trim());
if (missingPromo.length) throw new Error('Missing promo fields: ' + missingPromo.join(', '));
if (!md.brand) throw new Error('md.brand is required');
if (!md.designConcept && !md.designPromptContext) throw new Error('md.designConcept or md.designPromptContext is required');

return [{
  json: {
    id,
    model,
    imageModel,
    n8nWebhookUrl,
    promptUrl,
    md,
    promo,
    template,
    simpleBrief,
    sectionInputs,
    design,
    sourceDesign: body.sourceDesign || {},
    styleSource: body.styleSource || '',
    styleSourceLabel: body.styleSourceLabel || '',
    companyPreset: body.companyPreset || null,
    hasOverride: Boolean(body.hasOverride),
    output: {
      format: output.format || 'ui_design_image',
      stage: output.stage || 'design_image_generation',
      viewport: output.viewport || { width: 1440, minWidth: 1180 },
      imageSize: output.imageSize || '1536x1024'
    }
  }
}];

const input = $('Normalize Payload').item.json;
const loadedPrompt = $json;
const concept = input.md.designConcept || {};
const conceptJson = concept.json || {};
const summary = input.md.summary || {};
const promptContext = input.md.designPromptContext || concept.promptContext || '';

const promptTemplate = String(
  loadedPrompt.prompt ||
  loadedPrompt.body?.prompt ||
  loadedPrompt.data?.prompt ||
  ''
).trim();

if (!promptTemplate) {
  throw new Error('External UI design image prompt is empty');
}

const designBrief = {
  objective: 'Create a desktop promotional UI design image, not production HTML.',
  brand: input.md.brand,
  promoTitle: input.promo.title,
  market: input.promo.market,
  template: input.template,
  simpleBrief: input.simpleBrief,
  sectionInputs: input.sectionInputs,
  selectedStyleSource: input.styleSourceLabel,
  viewport: input.output.viewport,
  requiredContent: {
    promoTitle: input.promo.title,
    leadText: input.promo.leadText,
    ctaLabel: input.promo.ctaLabel,
    ctaUrl: input.promo.ctaUrl,
    subline: input.promo.subline,
    alphaLegalText: input.promo.alphaText || '',
    termsAndConditions: input.promo.termsText
  },
  designStyle: input.design,
  mdConceptSummary: concept.summary || conceptJson.brandConcept || '',
  mdPromptContext: promptContext,
  mdConceptJson: conceptJson,
  mdSummary: summary
};

const layoutMapping = {
  temp4Order: ['header', 'heroBanner', 'stepBar', 'contentCta', 'imageTextRow', 'titleDescription', 'footer'],
  header: ['sectionInputs.header.logoText', 'sectionInputs.header.badgeText'],
  hero: ['sectionInputs.heroBanner.leaderText', 'sectionInputs.heroBanner.title', 'sectionInputs.heroBanner.sublineText', 'sectionInputs.heroBanner.cta', 'sectionInputs.heroBanner.alphaText', 'sectionInputs.heroBanner.visualMode'],
  stepBar: ['sectionInputs.stepBar[0].title/description/link', 'sectionInputs.stepBar[1].title/description/link', 'sectionInputs.stepBar[2].title/description/link'],
  contentCta: ['sectionInputs.contentCta.longText', 'sectionInputs.contentCta.cta', 'sectionInputs.contentCta.visualMode'],
  imageTextRow: ['sectionInputs.imageTextRow.headerTitle', 'sectionInputs.imageTextRow.headerDescription', 'sectionInputs.imageTextRow.title', 'sectionInputs.imageTextRow.description', 'sectionInputs.imageTextRow.visualMode'],
  complianceFooter: ['sectionInputs.titleDescription.title', 'sectionInputs.titleDescription.contents', 'sectionInputs.footer.logoText', 'sectionInputs.footer.licenseBadges'],
  note: 'Use sectionInputs as the primary content contract. VisualMode controls whether each section uses an inferred visual.'
};

const mdComplianceKeys = [
  'layoutPhilosophy',
  'visualMood',
  'spacingRhythm',
  'composition',
  'componentStyle',
  'depthAndEffects',
  'shapeAndRadius',
  'promoPageImplications',
  'dosApplied',
  'dontsAvoided',
  'notColorFontOnlyProof'
];

const values = {
  imageSize: input.output.imageSize || '1536x1024',
  designBrief: JSON.stringify(designBrief, null, 2),
  layoutMapping: JSON.stringify(layoutMapping, null, 2),
  mdComplianceKeys: JSON.stringify(mdComplianceKeys)
};

const render = (template, data) => template.replace(/{{\s*([a-zA-Z0-9_]+)\s*}}/g, (match, key) => (
  Object.prototype.hasOwnProperty.call(data, key) ? String(data[key]) : match
));

const system = 'You are a senior promotional UI art director. Return valid JSON only. Your job is to write a precise image-generation prompt for a desktop promotional web UI mockup. The selected MD is binding, not inspiration.';
const user = render(promptTemplate, values);

return [{
  json: {
    ...input,
    designBrief,
    layoutMapping,
    promptMeta: {
      id: loadedPrompt.id || loadedPrompt.body?.id || 'external-promo-ui-design-image-generation',
      version: loadedPrompt.version || loadedPrompt.body?.version || '',
      url: input.promptUrl || 'https://promo-web-builder.vercel.app/api/prompts/promo-ui-design-image-generation'
    },
    llmRequest: {
      model: input.model,
      messages: [
        { role: 'system', content: system },
        { role: 'user', content: user }
      ],
      temperature: 0.22,
      response_format: { type: 'json_object' }
    }
  }
}];

const input = $('Build UI Design Prompt').item.json;
const response = $json;
const content = response.choices?.[0]?.message?.content || response.message?.content || response.content || response.text || response.output_text || '';
if (!content) throw new Error('LLM image prompt response is empty');

let generated;
try {
  const fence = String.fromCharCode(96, 96, 96);
  generated = typeof content === 'string'
    ? JSON.parse(content.replace(new RegExp('^' + fence + 'json\\s*', 'i'), '').replace(new RegExp(fence + '$', 'i'), '').trim())
    : content;
} catch (error) {
  throw new Error('Failed to parse image prompt JSON: ' + error.message);
}

if (!String(generated.imagePrompt || '').trim()) throw new Error('imagePrompt is required');
if (!generated.mdComplianceMap || typeof generated.mdComplianceMap !== 'object') throw new Error('mdComplianceMap is required');
if (!generated.layoutMapping || typeof generated.layoutMapping !== 'object') throw new Error('layoutMapping is required');

const requiredCompliance = [
  'layoutPhilosophy',
  'visualMood',
  'spacingRhythm',
  'composition',
  'componentStyle',
  'depthAndEffects',
  'shapeAndRadius',
  'promoPageImplications',
  'notColorFontOnlyProof'
];
const missingCompliance = requiredCompliance.filter((key) => !String(generated.mdComplianceMap[key] || '').trim());
if (missingCompliance.length) throw new Error('mdComplianceMap missing fields: ' + missingCompliance.join(', '));

const proof = String(generated.mdComplianceMap.notColorFontOnlyProof || '').trim();
if (proof.length < 40) throw new Error('mdComplianceMap.notColorFontOnlyProof is too weak');

const finalPrompt = [
  generated.imagePrompt,
  '',
  'Hard requirements:',
  '- Desktop promotional web UI mockup, 1440px-wide composition.',
  '- Show a complete page design, not a cropped component.',
  '- Include visible placements for promo title, lead text, CTA button, subline, and legal/terms footer.',
  '- No code, no browser chrome, no editor UI, no Figma canvas UI.',
  '- Make the layout reflect the selected MD design concept, not only colors and fonts.',
  '- Preserve Template 4 order: Header, Hero Banner, Step Bar, Content CTA, Image Text Row, Terms/Footer.',
  '- Follow the MD layout philosophy, spacing rhythm, composition, component style, depth/effects, shape/radius, dos, and donts.',
  generated.negativePrompt ? 'Avoid: ' + generated.negativePrompt : ''
].filter(Boolean).join('\n');

return [{
  json: {
    ...input,
    imagePrompt: finalPrompt,
    designBrief: generated.designBrief || input.designBrief,
    layoutMapping: generated.layoutMapping,
    mdComplianceMap: generated.mdComplianceMap
  }
}];

const input = $('Parse Validate Image Prompt').item.json;
const response = $json;
const imageUrlFromApi = response.data?.[0]?.url || response.output?.[0]?.url || '';
const b64 = response.data?.[0]?.b64_json || response.output?.[0]?.b64_json || response.image?.b64_json || '';
if (!imageUrlFromApi && !b64) throw new Error('Image generation response must include url or b64_json');

const imageDataUrl = b64 ? 'data:image/png;base64,' + b64 : '';
const staticData = $getWorkflowStaticData('global');
staticData.designs = staticData.designs || {};
staticData.designs[input.id] = {
  imageUrlFromApi,
  hasEmbeddedImage: Boolean(imageDataUrl),
  imagePrompt: input.imagePrompt,
  designBrief: input.designBrief,
  layoutMapping: input.layoutMapping,
  mdComplianceMap: input.mdComplianceMap,
  promptMeta: input.promptMeta,
  payload: input,
  createdAt: new Date().toISOString()
};

const queryPath = 'promo-ui-design-view?id=' + encodeURIComponent(input.id);
const sourceUrl = String(input.n8nWebhookUrl || '').trim();
const buildDesignUrl = (url) => {
  if (!url) return '';
  const replaced = url.replace(/promo-ui-design-generate\/?(?:\?.*)?$/, queryPath);
  if (replaced !== url) return replaced;
  try {
    const parsed = new URL(url);
    parsed.pathname = parsed.pathname.replace(/\/$/, '').replace(/promo-ui-design-generate$/, 'promo-ui-design-view');
    parsed.search = '?id=' + encodeURIComponent(input.id);
    return parsed.toString();
  } catch {
    return url.replace(/\/promo-ui-design-generate\/?(?:\?.*)?$/, '/' + queryPath);
  }
};
let designUrl = buildDesignUrl(sourceUrl);
if (!designUrl || /promo-ui-design-generate\/?(?:\?.*)?$/.test(designUrl)) {
  const headers = $('Generate Promo UI Design').item.json.headers || {};
  const proto = headers['x-forwarded-proto'] || 'https';
  const host = headers['x-forwarded-host'] || headers.host || '';
  designUrl = host ? proto + '://' + host + '/webhook/' + queryPath : '/webhook/' + queryPath;
}
const resultType = imageUrlFromApi || imageDataUrl ? 'image' : 'view';

return [{
  json: {
    ok: true,
    id: input.id,
    resultType,
    designUrl,
    imageUrl: imageUrlFromApi || imageDataUrl || '',
    hasEmbeddedImage: Boolean(imageDataUrl),
    designBrief: input.designBrief,
    layoutMapping: input.layoutMapping,
    mdComplianceMap: input.mdComplianceMap,
    promptMeta: input.promptMeta,
    imagePrompt: input.imagePrompt,
    payload: input
  }
}];

const id = $json.params?.id || $json.query?.id || '';
const staticData = $getWorkflowStaticData('global');
const design = staticData.designs?.[id];
const src = design?.imageUrlFromApi || '';
const title = design?.payload?.promo?.title || 'Promo UI Design';
const html = src
  ? `<!doctype html><html lang='ko'><head><meta charset='utf-8'><meta name='viewport' content='width=device-width,initial-scale=1'><title>${title}</title><style>body{margin:0;background:#f6f8fc;font-family:Arial,sans-serif;color:#111827}.wrap{max-width:1540px;margin:0 auto;padding:24px}.bar{display:flex;justify-content:space-between;gap:16px;align-items:center;margin-bottom:16px}.meta{color:#64748b;font-size:13px}.frame{border:1px solid #dfe6f2;background:white;border-radius:8px;overflow:hidden;box-shadow:0 14px 40px rgba(20,35,70,.08)}img{display:block;width:100%;height:auto}</style></head><body><main class='wrap'><div class='bar'><strong>${title}</strong><span class='meta'>${id}</span></div><div class='frame'><img src='${src}' alt='Generated promo UI design'></div></main></body></html>`
  : `<!doctype html><html lang='ko'><head><meta charset='utf-8'><title>UI design not found</title></head><body style='font-family:Arial,sans-serif;padding:40px'><h1>UI design not found</h1><p>No generated UI design was stored for id: ${id}</p></body></html>`;
return [{ json: { html } }];
